  const {
    control,
    formState: {
      errors
    }
  } = useForm<FormModel>({
    mode: 'all',
    defaultValues: {
      phone: '',
      phoneDisabled: '',
      phoneError: ''
    }
  });
  const {
    label,
    slotProps
  } = args;
  return <Fields>
      <FieldView>
        <RcSesPhoneInput id='phone' name='phone' control={control} rules={{
        required: true
      }} label={label} errors={errors?.phone} slotProps={slotProps} />
      </FieldView>

      <FieldPreviewRow>
        <PreviewTitle>State previews</PreviewTitle>
        <RcSesPhoneInput id='phoneDisabled' name='phoneDisabled' control={control} rules={{
        required: true
      }} label='Disabled' disabled errors={errors?.phoneDisabled} slotProps={slotProps} />
        <RcSesPhoneInput id='phoneError' name='phoneError' control={control} rules={{
        required: true
      }} label='Error' errors={{
        message: 'Error Message',
        type: 'required'
      }} slotProps={slotProps} />
      </FieldPreviewRow>
    </Fields>;
